/**
 * AURA TRADING DESK — AI Onboarding Wizard (5 Steps)
 * Full-page, no sidebar, dark theme.
 * Steps: Welcome → Choose Plan → Try It Out → Feature Tour → Activate
 *
 * Wired to backend endpoints:
 *   POST /api/wizard/start — start wizard session
 *   GET  /api/wizard/progress — get wizard progress
 *   GET  /api/wizard/recommendations — get strategy recommendations
 *   POST /api/wizard/complete — complete wizard
 *   POST /api/ai/strategy-selector/select-strategies — AI strategy selection
 *   GET  /api/ai/strategy-selector/strategy-suggestions — AI suggestions
 *   GET  /api/strategies — strategy catalogue
 */
import React, { useState, useEffect, useRef, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import { getApiBase } from '../utils/platform';
import usePageTitle from '../hooks/usePageTitle';
import { SkeletonCard } from '../components/SkeletonUI';
import { tokens } from '../styles/tokens';
import { AI_ADDON_PRICING } from '../config/pricing';
import s from './AIOnboardingWizardPage.module.css';

const C = {
  bg: tokens.color.bg, surface: tokens.color.surface, surface2: tokens.color.surfaceHover,
  border: tokens.color.border, textPrimary: tokens.color.text, textSecondary: tokens.color.textSecondary,
  green: tokens.color.green, red: tokens.color.red, blue: tokens.color.blue,
  amber: tokens.color.amber, purple: tokens.color.purple,
};

function authHeaders() {
  const token = localStorage.getItem('aura_token');
  return token ? { Authorization: `Bearer ${token}` } : {};
}

const STEP_LABELS = ['Welcome', 'Choose Plan', 'Try It Out', 'Feature Tour', 'Activate'];

// ── Shared Components ─────────────────────────────────────────────────────

function StepIndicator({ current }) {
  return (
    <div className={s.stepIndicator}>
      {STEP_LABELS.map((label, i) => (
        <React.Fragment key={i}>
          {i > 0 && (
            <div className={s.stepConnector} style={{
              background: i <= current ? C.purple : C.border,
            }} />
          )}
          <div className={s.stepDot}>
            <div className={s.stepCircle} style={{
              background: i < current ? C.purple : i === current ? C.surface2 : 'transparent',
              border: i <= current ? `2px solid ${C.purple}` : `2px solid ${C.border}`,
              color: i <= current ? C.textPrimary : C.textSecondary,
            }}>
              {i < current ? '\u2713' : i + 1}
            </div>
            <span className={s.stepLabel} style={{
              color: i === current ? C.textPrimary : C.textSecondary,
              fontWeight: i === current ? 600 : 400,
            }}>
              {label}
            </span>
          </div>
        </React.Fragment>
      ))}
    </div>
  );
}

function NavButtons({ onBack, onNext, nextLabel = 'Continue', nextDisabled = false, loading = false, backLabel = 'Back' }) {
  return (
    <div className={s.navRow}>
      {onBack ? (
        <button onClick={onBack} className={s.btnSecondary}>{backLabel}</button>
      ) : <div />}
      {nextLabel && (
        <button onClick={onNext} disabled={nextDisabled || loading}
          className={s.btnPrimary}
          style={{ opacity: nextDisabled || loading ? 0.5 : 1, cursor: nextDisabled || loading ? 'not-allowed' : 'pointer' }}>
          {loading ? 'Processing...' : nextLabel}
        </button>
      )}
    </div>
  );
}

