// ── Step 4: Activate ──────────────────────────────────────────────────────

function StepActivate({ onBack, selectedTier }) {
  const navigate = useNavigate();
  const [agreed, setAgreed] = useState(false);
  const [activating, setActivating] = useState(false);
  const [error, setError] = useState('');

  const tierInfo = FALLBACK_TIERS.find(t => t.key === selectedTier) || {
    key: selectedTier, label: selectedTier, price: 0,
    monthly_token_limit: 50000, models: ['Haiku'], deep_analysis: false,
  };

  const handleActivate = async () => {
    setActivating(true);
    setError('');

    try {
      // Complete the wizard session via /api/wizard/complete
      try {
        await fetch(`${getApiBase()}/wizard/complete`, {
          method: 'POST',
          headers: { ...authHeaders(), 'Content-Type': 'application/json' },
          body: JSON.stringify({ ai_tier: selectedTier, completed: true }),
        });
      } catch (e) {
        // Non-critical, continue with activation
      }

      if (selectedTier === 'trial') {
        const trialRes = await fetch(`${getApiBase()}/subscriptions/enable-trial`, {
          method: 'POST',
          headers: { ...authHeaders(), 'Content-Type': 'application/json' },
        });
        if (!trialRes.ok) {
          const data = await trialRes.json().catch(() => ({}));
          throw new Error(data.detail || data.error || 'Failed to start trial');
        }

        await fetch(`${getApiBase()}/onboarding/ai/complete`, {
          method: 'POST',
          headers: { ...authHeaders(), 'Content-Type': 'application/json' },
        });

        navigate('/ai/chat', { replace: true });
      } else {
        await fetch(`${getApiBase()}/onboarding/ai/complete`, {
          method: 'POST',
          headers: { ...authHeaders(), 'Content-Type': 'application/json' },
        });

        const checkoutRes = await fetch(`${getApiBase()}/subscriptions/checkout`, {
          method: 'POST',
          headers: { ...authHeaders(), 'Content-Type': 'application/json' },
          body: JSON.stringify({ tier: selectedTier }),
        });
        const checkoutData = await checkoutRes.json();

        if (checkoutData.checkout_url) {
          window.location.href = checkoutData.checkout_url;
        } else {
          throw new Error(checkoutData.detail || checkoutData.error || 'Checkout failed');
        }
      }
    } catch (err) {
      setError(err.message || 'Something went wrong. Please try again.');
      setActivating(false);
    }
  };

  const isReady = agreed && !activating;

  return (
    <div className={s.activateWrap}>
      <h2 className={s.sectionTitle}>Activate Your AI Assistant</h2>
      <p className={s.sectionDesc}>Review your selection and get started</p>

      {/* Plan Summary Card */}
      <div className={`${s.card} ${s.planSummary}`} style={{
        borderColor: C.purple + '50',
        background: `linear-gradient(135deg, ${C.surface}, ${C.purple}08)`,
      }}>
        <div className={s.planSummaryLabel}>Selected Plan</div>
        <div className={s.planSummaryHeader}>
          <div className={s.planSummaryName}>{tierInfo.label}</div>
          <div className={s.tierPriceWrap}>
            <span className={s.tierPrice}>${tierInfo.price}</span>
            {tierInfo.price > 0 && <span className={s.tierPeriod}>/mo</span>}
            {tierInfo.price === 0 && (
              <span className={s.tierTrial} style={{ marginLeft: 8 }}>14-day free trial</span>
            )}
          </div>
        </div>

        <div className={s.planSummaryGrid}>
          <div>
            <div className={s.planDetailLabel}>Monthly Tokens</div>
            <div className={s.planDetailMono}>{formatTokens(tierInfo.monthly_token_limit)}</div>
          </div>
          <div>
            <div className={s.planDetailLabel}>Models</div>
            <div className={s.planDetailValue}>{tierInfo.models.join(' + ')}</div>
          </div>
          <div>
            <div className={s.planDetailLabel}>Deep Analysis</div>
            <div className={s.planDetailValue} style={{
              color: tierInfo.deep_analysis ? C.green : C.textSecondary,
            }}>
              {tierInfo.deep_analysis ? 'Included' : 'Not included'}
            </div>
          </div>
          <div>
            <div className={s.planDetailLabel}>Billing</div>
            <div className={s.planDetailValue}>
              {tierInfo.price === 0 ? 'Free for 14 days' : 'Monthly'}
            </div>
          </div>
        </div>
      </div>

      {/* Terms Checkbox */}
      <div
        onClick={() => setAgreed(!agreed)}
        className={s.termsRow}
        style={{ border: `1px solid ${agreed ? C.purple + '50' : C.border}` }}
      >
        <div className={s.checkbox} style={{
          border: `2px solid ${agreed ? C.purple : C.border}`,
          background: agreed ? C.purple : 'transparent',
        }}>
          {agreed && <span className={s.checkMark}>{'\u2713'}</span>}
        </div>
        <div className={s.termsText}>
          I agree to the <span className={s.termsLink}>Terms of Service</span> and
          understand billing will begin after any trial period.
          {tierInfo.price > 0 && (
            <span> My card will be charged <strong className={s.termsBold}>${tierInfo.price}/month</strong>.</span>
          )}
        </div>
      </div>

      {/* Error */}
      {error && (
        <div className={s.errorBox}>
          {typeof error === 'string' ? error : error?.message || 'An error occurred'}
        </div>
      )}

      {/* Activate Button */}
      <button
        onClick={handleActivate}
        disabled={!agreed || activating}
        className={`${s.activateBtn} ${isReady ? s.activateBtnReady : s.activateBtnDisabled}`}
        style={isReady ? {
          background: `linear-gradient(135deg, ${C.purple}, ${C.blue})`,
          boxShadow: `0 4px 24px ${C.purple}30`,
        } : undefined}
      >
        {activating
          ? 'Activating...'
          : selectedTier === 'trial'
            ? 'Start Free Trial'
            : `Activate AI Assistant - $${tierInfo.price}/mo`
        }
      </button>

      <NavButtons onBack={onBack} onNext={() => {}} nextLabel="" />
    </div>
  );
}

// ── Main Wizard Container ─────────────────────────────────────────────────

export default function AIOnboardingWizardPage() {
  usePageTitle('AI Setup');
  const navigate = useNavigate();
  const [step, setStep] = useState(0);
  const [selectedTier, setSelectedTier] = useState('trial');
  const [loading, setLoading] = useState(true);
  const [strategyCatalogue, setStrategyCatalogue] = useState([]);

  // Check if user already completed AI onboarding + restore wizard progress
  useEffect(() => {
    const checkStatus = async () => {
      try {
        const res = await fetch(`${getApiBase()}/onboarding/ai/status`, {
          headers: authHeaders(),
        });
        if (res.ok) {
          const data = await res.json();
          if (data.ai_onboarding_completed) {
            navigate('/ai/chat', { replace: true });
            return;
          }
          if (typeof data.ai_onboarding_step === 'number' && data.ai_onboarding_step > 0) {
            setStep(data.ai_onboarding_step);
          }
        }
      } catch (e) {
        console.warn('Could not check AI onboarding status:', e);
      }

      // Try restoring wizard progress
      try {
        const wizRes = await fetch(`${getApiBase()}/wizard/progress`, {
          headers: authHeaders(),
        });
        if (wizRes.ok) {
          const wizData = await wizRes.json();
          if (wizData.ai_tier) setSelectedTier(wizData.ai_tier);
        }
      } catch (e) {
        // Non-critical
      }

      // Fetch strategy catalogue for reference
      try {
        const catRes = await fetch(`${getApiBase()}/strategies`, {
          headers: authHeaders(),
        });
        if (catRes.ok) {
          const catData = await catRes.json();
          if (Array.isArray(catData)) {
            setStrategyCatalogue(catData);
          } else if (catData.strategies) {
            setStrategyCatalogue(catData.strategies);
          }
        }
      } catch (e) {
        // Non-critical
      }

      setLoading(false);
    };
    checkStatus();
  }, [navigate]);

  // Save step progress (both to AI onboarding and wizard endpoints)
  const saveStep = useCallback(async (stepNum) => {
    try {
      await fetch(`${getApiBase()}/onboarding/ai/step`, {
        method: 'POST',
        headers: { ...authHeaders(), 'Content-Type': 'application/json' },
        body: JSON.stringify({ step: stepNum }),
      });
    } catch (e) {
      // Non-critical, continue
    }
    // Also start/update wizard session
    if (stepNum === 1) {
      try {
        await fetch(`${getApiBase()}/wizard/start`, {
          method: 'POST',
          headers: { ...authHeaders(), 'Content-Type': 'application/json' },
          body: JSON.stringify({ ai_onboarding: true, ai_tier: selectedTier }),
        });
      } catch (e) {
        // Non-critical
      }
    }
  }, [selectedTier]);

  const goNext = useCallback(() => {
    setStep(s => {
      const next = Math.min(s + 1, 4);
      saveStep(next);
      return next;
    });
  }, [saveStep]);

  const goBack = useCallback(() => {
    setStep(s => Math.max(s - 1, 0));
  }, []);

  if (loading) {
    return (
      <div className={s.loadingWrap}>
        <SkeletonCard width={480} height={320} />
      </div>
    );
  }

  return (
    <div className={s.page} style={{
      background: `radial-gradient(ellipse at 20% 50%, rgba(188,140,255,0.08), transparent 60%),
                   radial-gradient(ellipse at 80% 20%, rgba(88,166,255,0.06), transparent 50%),
                   ${C.bg}`,
    }}>
      <div className={s.pageInner}>
        {step > 0 && <StepIndicator current={step} />}

        <div className={step === 0 ? s.stepAreaWelcome : s.stepArea}>
          {step === 0 && <StepWelcome onNext={goNext} />}
          {step === 1 && (
            <StepChoosePlan
              onNext={goNext}
              onBack={goBack}
              selectedTier={selectedTier}
              setSelectedTier={setSelectedTier}
            />
          )}
          {step === 2 && <StepTryItOut onNext={goNext} onBack={goBack} />}
          {step === 3 && <StepFeatureTour onNext={goNext} onBack={goBack} />}
          {step === 4 && <StepActivate onBack={goBack} selectedTier={selectedTier} />}
        </div>
      </div>
    </div>
  );
}
